TriggerOraclev10g.body:
DECLARE
    v_json_correo   JSON_OBJECT_T;
    v_clob_correo   CLOB;
BEGIN
    IF :new.recomienda_servicio < 9
    THEN
        --Envio de correo a coordinadores
        v_json_correo := JSON_OBJECT_T ();
        v_json_correo.put ('id_plantilla', 128);
        v_json_correo.put ('id_cita', :new.id_cita);
        v_json_correo.put ('calificacion', :new.recomienda_servicio);
        v_clob_correo := v_json_correo.TO_CLOB ();
        pkgln_mensajes.p_enviar_correo (v_clob_correo);
    END IF;
END;
